content:
{
  "sentences": [
    {
      "text": "你好，我想要一杯小杯的拿鐵，可以嗎？",
      "pinyin": "Nǐ hǎo, wǒ xiǎng yào yī bēi xiǎo bēi de ná tiě, kě yǐ ma?",
      "pinyin_numeric": "ni3 hao3, wo3 xiang3 yao4 yi1 bei1 xiao3 bei1 de5 na2 tie3, ke3 yi3 ma0?",
      "translation_en": "Hello, I would like a small latte, okay?",
      "translation_ko": "안녕하세요, 작은 라떼 한 잔을 원하는데 괜찮을까요?"
    },
    {
      "text": "麻煩你，可以給我一杯冰的紅茶嗎？",
      "pinyin": "Má fan nǐ, kě yǐ gěi wǒ yī bēi bīng de hóng chá ma?",
      "pinyin_numeric": "ma2 fan5 ni3, ke3 yi3 gei3 wo3 yi1 bei1 bing1 de5 hong2 cha2 ma0?",
      "translation_en": "Excuse me, could you give me an iced black tea?",
      "translation_ko": "실례합니다, 얼음 홍차 한 잔 주시겠어요?"
    },
    {
      "text": "不好意思，可以幫我加珍珠嗎？",
      "pinyin": "Bù hǎo yì si, kě yǐ bāng wǒ jiā zhēn zhū ma?",
      "pinyin_numeric": "bu4 hao3 yi4 si5, ke3 yi3 bang1 wo3 jia1 zhen1 zhu1 ma0?",
      "translation_en": "Excuse me, could you add boba for me?",
      "translation_ko": "죄송합니다, 타피오카 펄을 추가해 주시겠어요?"
    },
    {
      "text": "店員，可以給我一個袋子嗎？",
      "pinyin": "Diàn yuán, kě yǐ gěi wǒ yī gè dài zi ma?",
      "pinyin_numeric": "dian4 yuan2, ke3 yi3 gei3 wo3 yi1 ge4 dai4 zi5 ma0?",
      "translation_en": "Shop assistant, could you give me a bag?",
      "translation_ko": "점원님, 봉투 하나 주시겠어요?"
    },
    {
      "text": "請問，可以幫我外帶嗎？",
      "pinyin": "Qǐng wèn, kě yǐ bāng wǒ wài dài ma?",
      "pinyin_numeric": "qing3 wen4, ke3 yi3 bang1 wo3 wai4 dai4 ma0?",
      "translation_en": "Excuse me, could you make it for takeout?",
      "translation_ko": "실례합니다, 포장해 주시겠어요?"
    },
    {
      "text": "可以給我半糖的豆漿嗎？",
      "pinyin": "Kě yǐ gěi wǒ bàn táng de dòu jiāng ma?",
      "pinyin_numeric": "ke3 yi3 gei3 wo3 ban4 tang2 de5 dou4 jiang1 ma0?",
      "translation_en": "Could you give me half-sugar soy milk?",
      "translation_ko": "반당 두유를 주시겠어요?"
    },
    {
      "text": "麻煩你，可以給我一根吸管嗎？",
      "pinyin": "Má fan nǐ, kě yǐ gěi wǒ yī gēn xī guǎn ma?",
      "pinyin_numeric": "ma2 fan5 ni3, ke3 yi3 gei3 wo3 yi1 gen1 xi1 guan3 ma0?",
      "translation_en": "Excuse me, could you give me a straw?",
      "translation_ko": "실례합니다, 빨대 하나 주시겠어요?"
    },
    {
      "text": "不好意思，可以再說一次價錢嗎？",
      "pinyin": "Bù hǎo yì si, kě yǐ zài shuō yī cì jià qián ma?",
      "pinyin_numeric": "bu4 hao3 yi4 si5, ke3 yi3 zai4 shuo1 yi1 ci4 jia4 qian2 ma0?",
      "translation_en": "Excuse me, could you say the price again?",
      "translation_ko": "죄송합니다, 가격을 한 번 더 말씀해 주시겠어요?"
    },
    {
      "text": "可以給我中杯的綠茶，少冰嗎？",
      "pinyin": "Kě yǐ gěi wǒ zhōng bēi de lǜ chá, shǎo bīng ma?",
      "pinyin_numeric": "ke3 yi3 gei3 wo3 zhong1 bei1 de5 lü4 cha2, shao3 bing1 ma0?",
      "translation_en": "Could you give me a medium green tea with less ice?",
      "translation_ko": "중간 컵 녹차를 얼음 적게 해서 주시겠어요?"
    },
    {
      "text": "店員，可以幫我內用嗎？",
      "pinyin": "Diàn yuán, kě yǐ bāng wǒ nèi yòng ma?",
      "pinyin_numeric": "dian4 yuan2, ke3 yi3 bang1 wo3 nei4 yong4 ma0?",
      "translation_en": "Shop assistant, could you serve it for here?",
      "translation_ko": "점원님, 매장에서 먹을 수 있게 해 주시겠어요?"
    }
  ]
}
